import React, { useState } from 'react';

const allProjects = [
  [
    { href: '#', img: '/images/technicaldocument.png', title: 'Technical Document Web Page', desc: 'Documentation site' },
    { href: '#', img: '/images/survey.png', title: 'Survey', desc: 'Feedback form' },
  ],
];

const Projects = () => {
  const [current, setCurrent] = useState(0);

  return (
    <section
      id="Projects"
      style={{ background: '#112240', fontFamily: "'Orbitron', sans-serif" }}
      className="flex flex-col items-center px-10 pt-24 pb-16"
    >
      <h1 className="text-white text-4xl font-bold mb-12">My Projects</h1>

      <div className="flex gap-6 flex-wrap">
        {allProjects[current].map((p, i) => (
          <div
            key={i}
            style={{
              background: '#f8f9fa',
              borderLeft: '5px solid #0d6efd',
              borderRadius: '12px',
              width: '220px',
              padding: '10px',
            }}
          >
            <img src={p.img} alt="" style={{ width: '100%', borderRadius: '8px' }} />
            <h4 style={{ color: '#0b1f3a' }}>{p.title}</h4>
            <p>{p.desc}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Projects;
